/**
 * Hand-curated app-level row types — NOT a generated artifact.
 *
 * These interfaces describe the subset of columns the application
 * code reads and are narrower / more opinionated than the raw
 * `Database['public']['Tables'][…]['Row']` types generated by the
 * Supabase CLI. They are imported by DAL helpers, server components,
 * and the admin UI wherever typed row objects are needed without the
 * full Insert/Update generics.
 *
 * Source of truth: this file is hand-edited.  Whenever a column is
 * added, renamed, or dropped in a migration, update the matching
 * interface here in the same PR.
 *
 * See also:
 *   - `types/supabase.ts`                — GENERATED `Database` type
 *                                          consumed by
 *                                          `createClient<Database>()`.
 *   - `scripts/check-schema-drift.sh`    — regenerates `types/supabase.ts`
 *                                          from the live DB; this file
 *                                          is intentionally NOT regenerated.
 */

// ── Newsletter Subscribers ─────────────────────────────────────────────

export type NewsletterStatus = "pending" | "active" | "unsubscribed";

export interface NewsletterSubscriberRow {
  id: string;
  site_id: string;
  email: string;
  status: NewsletterStatus;
  /** Double opt-in token — cleared after confirmation */
  confirmation_token: string | null;
  confirmed_at: string | null;
  /** Opaque capability token for one-click unsubscribe links */
  unsubscribe_token: string | null;
  created_at: string;
}

